-- Correction : Bora ne tourne PAS en local. Retrait de « en local » (Bora + coach JoyTrain), Mistral conservé.
BEGIN;

UPDATE projects SET short_description = 'Le moteur d''IA qui fait répondre le coach JoyTrain à partir de vraies sources reconnues, au lieu d''inventer.', architecture = 'Le moteur collecte des documents de référence, les découpe et les indexe. Le sens du texte est capté par des embeddings open source (bge-m3) stockés dans une base vectorielle PostgreSQL/pgvector. La recherche combine mots-clés et sens, fusionnés pour ne rater ni un terme précis comme « créatine » ni une formulation différente.', features = ARRAY['Réponses appuyées sur de vraies sources reconnues (santé, nutrition, science)', 'Retrouve l''information la plus pertinente pour chaque question posée', 'Tient compte du contexte de l''utilisateur pour mieux cibler la réponse', 'Recherche hybride : comprend le sens ET retrouve les termes techniques exacts', 'Chaque réponse reste rattachée à sa source d''origine', 'S''appuie sur Mistral, sans dépendre d''une IA propriétaire payante', 'Brique IA de l''écosystème JoyTrain (app + moteur Bora + site vitrine)']::text[], updated_at = now() WHERE slug = 'bora-rag-joytrain';

UPDATE projects SET features = ARRAY['Suivi d''entraînement complet : exercices, programmes, cardio et records personnels', 'Coach IA conversationnel « Bora » propulsé par Mistral (sans IA propriétaire payante), qui répond et génère des séances sur mesure', 'Scan d''un repas par photo pour estimer automatiquement les apports', 'Journal nutrition adossé à une vraie base alimentaire et ses macros', 'Couche sociale : amis, posts, messagerie et notifications en temps réel', 'Mode hors-ligne : on enregistre ses séances sans réseau, tout se synchronise ensuite', 'Graphiques de progression et atlas musculaire interactif', 'Prête pour les stores (TestFlight iOS et Google Play)']::text[], updated_at = now() WHERE slug = 'joytrain';

COMMIT;
